module RefModule(clk, WE, RE, din, dout);  
    input clk;  
    input WE;  
    input RE;  
    input [3:0] din;  
    output reg [3:0] dout;  
    reg [3:0] unused_storage;  

    always @(posedge clk) begin  
        if (WE) begin  
            unused_storage <= din;  
        end  
        if (RE) begin  
            dout <= unused_storage;  
        end  
    end  
endmodule
